import{_ as a,o as t,c as e,a2 as s}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"Billing","description":"Cost tracking, quotas, and billing reports","frontmatter":{"title":"Billing","description":"Cost tracking, quotas, and billing reports"},"headers":[],"relativePath":"guide/billing.md","filePath":"guide/billing.md"}'),n={name:"guide/billing.md"};function l(r,i,o,d,p,h){return t(),e("div",null,[...i[0]||(i[0]=[s(`<h1 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>WebRouter tracks token usage and costs in real time. The billing dashboard provides:</p><ul><li>Per-model cost breakdown</li><li>Per-token and per-organization usage</li><li>Historical trends (30 days)</li><li>Quota management</li><li>Budget alerts</li></ul><h2 id="cost-tracking" tabindex="-1">Cost Tracking <a class="header-anchor" href="#cost-tracking" aria-label="Permalink to &quot;Cost Tracking&quot;">​</a></h2><h3 id="per-model-pricing" tabindex="-1">Per-Model Pricing <a class="header-anchor" href="#per-model-pricing" aria-label="Permalink to &quot;Per-Model Pricing&quot;">​</a></h3><p>Configure pricing in <strong>Settings</strong> → <strong>Model Pricing</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-4o&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;input_price&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;output_price&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10.00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;unit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;per million tokens&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Default pricing is pre-configured for common models and can be customized.</p><h3 id="request-logs" tabindex="-1">Request Logs <a class="header-anchor" href="#request-logs" aria-label="Permalink to &quot;Request Logs&quot;">​</a></h3><p>Every request processed by wr-proxy is logged with:</p><ul><li>Model, provider, token used</li><li>Input/output token counts</li><li>Cost (calculated from pricing)</li><li>Latency, status, error info</li></ul><p>30 days of request history are maintained and viewable in the billing dashboard.</p><h2 id="quotas" tabindex="-1">Quotas <a class="header-anchor" href="#quotas" aria-label="Permalink to &quot;Quotas&quot;">​</a></h2><p>Quotas can be set at the token level:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Total quota</td><td>Maximum tokens allowed</td></tr><tr><td>Used</td><td>Consumed tokens (auto-tracked)</td></tr><tr><td>Remaining</td><td>Auto-calculated</td></tr></tbody></table><p>When quota is depleted, the token stops working (unless smart downgrade is enabled).</p><h2 id="reports" tabindex="-1">Reports <a class="header-anchor" href="#reports" aria-label="Permalink to &quot;Reports&quot;">​</a></h2><p>Export billing data as CSV:</p><ul><li><strong>Token report</strong> — usage per token over a date range</li><li><strong>Provider report</strong> — usage per provider</li><li><strong>Model report</strong> — usage per model</li></ul><p>Data can be filtered by date range and organization.</p>`,21)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
